type monitorTagJoins[Q dialect.Joinable] struct {
	typ     string
	Tag     modAs[Q, tagColumns]
	Monitor modAs[Q, monitorColumns]
}

func (j monitorTagJoins[Q]) aliasedAs(alias string) monitorTagJoins[Q] {
	return buildMonitorTagJoins[Q](buildMonitorTagColumns(alias), j.typ)
}

func buildMonitorTagJoins[Q dialect.Joinable](cols monitorTagColumns, typ string) monitorTagJoins[Q] {
	return monitorTagJoins[Q]{
		typ: typ,
		Tag: modAs[Q, tagColumns]{
			c: Tags.Columns,
			f: func(to tagColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Tags.Name().As(to.Alias())).On(
						to.ID.EQ(cols.TagID),
					))
				}

				return mods
			},
		},
		Monitor: modAs[Q, monitorColumns]{
			c: Monitors.Columns,
			f: func(to monitorColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Monitors.Name().As(to.Alias())).On(
						to.ID.EQ(cols.MonitorID),
					))
				}

				return mods
			},
		},
	}
}
